@st.cache_resource(show_spinner=False)
def load_model():
    path = os.path.join(os.path.dirname(__file__), 'model', 'model.pkl')
    if not os.path.exists(path):
        return None
    with open(path, 'rb') as f:
        return pickle.load(f)

# ══════════════════════════════════════════════════════════════════
#  PREDICTION ENGINE
# ══════════════════════════════════════════════════════════════════
def predict_url(url, bundle):
    model   = bundle['model']
    f_names = bundle['feature_names']
    feats   = extract_features(url)
    vec     = [[feats[c] for c in f_names]]
    proba   = model.predict_proba(vec)[0]
    p_phish = float(proba[1])
    p_safe  = float(proba[0])
    if p_phish < 0.35:
        label, chip, chip_cls, card_cls = "Safe",       "✔ VERIFIED SAFE",     "chip-safe",  "glass-card-safe"
    elif p_phish < 0.65:
        label, chip, chip_cls, card_cls = "Suspicious", "⚠ SUSPICIOUS",        "chip-warn",  "glass-card-warn"
    else:
        label, chip, chip_cls, card_cls = "Phishing",   "✕ PHISHING DETECTED", "chip-error", "glass-card-error"
    return {
        'label': label, 'chip': chip, 'chip_cls': chip_cls, 'card_cls': card_cls,
        'risk_score': int(p_phish * 100),
        'confidence': round(max(p_phish, p_safe) * 100, 1),
        'phish_prob': round(p_phish * 100, 1),
        'safe_prob' : round(p_safe  * 100, 1),
        'features'  : feats,
        'warnings'  : explain_features(feats, url),
    }

