def _make_mini_chips(f):
    items = [
        (f["has_https"],1,"HTTPS"),
        (f["has_ip"],0,"No IP"),
        (f["has_suspicious_keyword"],0,"No Kwords"),
        (f["suspicious_tld"],0,"Safe TLD"),
    ]
    parts = []
    for v, good, lbl in items:
        bg  = "#e8f5e9" if v == good else "#ffdad6"
        col = "#2e7d32" if v == good else "#ba1a1a"
        sym = "✔" if v == good else "✘"
        parts.append(
            f'<div style="text-align:center;background:{bg};border-radius:8px;padding:8px;">' +
            f'<div style="font-family:var(--font-mono);font-size:.63rem;color:var(--on-surface-variant);">{lbl}</div>' +
            f'<div style="font-family:var(--font-display);font-size:.95rem;font-weight:700;color:{col};">{sym}</div>' +
            '</div>'
        )
    return "".join(parts)

def make_gauge(score):
    if score < 35:   color, label = "#2e7d32", "LOW RISK"
    elif score < 65: color, label = "#ed6c02", "MODERATE"
    else:            color, label = "#ba1a1a", "HIGH RISK"

    fig = go.Figure(go.Indicator(
        mode  = "gauge+number",
        value = score,
        number= {'suffix':"%", 'font':{'family':'Space Grotesk','size':38,'color':color}},
        gauge = {
            'axis'   : {'range':[0,100],'tickcolor':'#c1c6d5','tickfont':{'size':10,'color':'#727784'}},
            'bar'    : {'color':color,'thickness':.25},
            'bgcolor': '#fff','bordercolor':'#e2e8f0','borderwidth':1,
            'steps'  : [
                {'range':[0, 35],'color':'#e8f5e9'},
                {'range':[35,65],'color':'#fff3e0'},
                {'range':[65,100],'color':'#ffdad6'},
            ],
            'threshold': {'line':{'color':color,'width':3},'thickness':.85,'value':score},
        }
    ))
    fig.add_annotation(text=f'<b>{label}</b>', x=.5, y=-.18, showarrow=False,
                       font={'family':'JetBrains Mono','size':11,'color':color})
    fig.update_layout(
        paper_bgcolor='rgba(0,0,0,0)', plot_bgcolor='rgba(0,0,0,0)',
        font_color='#111c2d', height=240, margin=dict(l=20,r=20,t=30,b=40)
    )
    return fig

def make_line_chart(history):
    dates = [h['time'] for h in history[-20:]]
    safe  = [1 if h['label']=='Safe' else 0 for h in history[-20:]]
    phish = [1 if h['label']=='Phishing' else 0 for h in history[-20:]]
    fig = go.Figure()
    fig.add_trace(go.Scatter(x=dates, y=safe, name='Safe', fill='tozeroy',
        line=dict(color='#2e7d32',width=2.5), fillcolor='rgba(46,125,50,.1)'))
    fig.add_trace(go.Scatter(x=dates, y=phish, name='Phishing', fill='tozeroy',
        line=dict(color='#ba1a1a',width=2.5), fillcolor='rgba(186,26,26,.1)'))
    fig.update_layout(
        paper_bgcolor='rgba(0,0,0,0)', plot_bgcolor='rgba(0,0,0,0)',
        font_color='#111c2d', height=240, margin=dict(l=10,r=10,t=10,b=30),
        legend=dict(font=dict(family='JetBrains Mono',size=10,color='#727784')),
        xaxis=dict(showgrid=False,color='#727784',tickfont=dict(family='JetBrains Mono',size=9)),
        yaxis=dict(showgrid=True,gridcolor='#f0f3ff',color='#727784',tickfont=dict(size=9)),
    )
    return fig

def make_donut(safe_n, susp_n, phish_n):
    fig = go.Figure(go.Pie(
        labels=['Safe','Suspicious','Phishing'],
        values=[max(safe_n,1), max(susp_n,0), max(phish_n,0)],
        hole=.6, marker=dict(colors=['#2e7d32','#ed6c02','#ba1a1a'],
        line=dict(color='#fff',width=2)),
        textfont=dict(family='JetBrains Mono',size=11),
    ))
    total = safe_n + susp_n + phish_n
    fig.update_layout(
        paper_bgcolor='rgba(0,0,0,0)', plot_bgcolor='rgba(0,0,0,0)',
        height=220, margin=dict(l=10,r=10,t=10,b=10),
        showlegend=True, legend=dict(font=dict(family='JetBrains Mono',size=10)),
        annotations=[dict(text=f'<b>{total}</b><br><span style="font-size:10px">SCANNED</span>',
                          x=.5,y=.5,font_size=16,font_color='#111c2d',showarrow=False)]
    )
    return fig

def make_feature_bar(feats):
    display = {
        'URL Length': feats['url_length'], 'Dots': feats['num_dots'],
        'Hyphens': feats['num_hyphens'], 'Digits': feats['num_digits'],
        'Query Length': feats['query_length'], 'Keywords': feats['keyword_count'],
        'Entropy': feats['url_entropy'], 'Subdomains': feats['subdomain_count'],
    }
    vals   = list(display.values())
    mx     = max(vals) if max(vals) > 0 else 1
    normed = [v/mx*100 for v in vals]
    colors = ['#ba1a1a' if n>65 else '#ed6c02' if n>35 else '#2e7d32' for n in normed]
    fig = go.Figure(go.Bar(
        x=normed, y=list(display.keys()), orientation='h',
        marker_color=colors, text=[str(round(v,2)) for v in vals],
        textposition='outside', textfont=dict(family='JetBrains Mono',size=10,color='#727784'),
    ))
    fig.update_layout(
        paper_bgcolor='rgba(0,0,0,0)', plot_bgcolor='rgba(0,0,0,0)',
        font_color='#111c2d', height=300, margin=dict(l=10,r=60,t=10,b=10),
        xaxis=dict(showgrid=False,zeroline=False,showticklabels=False),
        yaxis=dict(color='#414753',tickfont=dict(family='JetBrains Mono',size=11)),
    )
    return fig

def make_importance_chart(bundle):
    imps   = bundle['rf_component'].feature_importances_
    fnames = bundle['feature_names']
    idx    = np.argsort(imps)[-10:]
    names  = [fnames[i].replace('_',' ').title() for i in idx]
    vals   = [imps[i] for i in idx]
    fig = go.Figure(go.Bar(
        x=vals, y=names, orientation='h', marker_color='#0066cc',
        text=[f'{v:.3f}' for v in vals], textposition='outside',
        textfont=dict(family='JetBrains Mono',size=10,color='#727784'),
    ))
    fig.update_layout(
        paper_bgcolor='rgba(0,0,0,0)', plot_bgcolor='rgba(0,0,0,0)',
        font_color='#111c2d', height=300, margin=dict(l=10,r=60,t=10,b=10),
        xaxis=dict(showgrid=False,zeroline=False,showticklabels=False),
        yaxis=dict(color='#414753',tickfont=dict(family='JetBrains Mono',size=10)),
    )
    return fig

